<?php
 namespace WPAICG\Chat\Frontend\Shortcode\FeatureManagerMethods; use WPAICG\Chat\Storage\BotSettingsManager; if (!defined('ABSPATH')) { exit; } function get_google_grounding_flags_logic(array $settings, bool $allow_google_search_grounding_setting): array { $grounding_flags = []; if (!class_exists(BotSettingsManager::class)) { $defaults = [ 'DEFAULT_GOOGLE_GROUNDING_MODE' => 'DEFAULT_MODE', 'DEFAULT_GOOGLE_GROUNDING_DYNAMIC_THRESHOLD' => 0.3, ]; } else { $defaults = [ 'DEFAULT_GOOGLE_GROUNDING_MODE' => BotSettingsManager::DEFAULT_GOOGLE_GROUNDING_MODE, 'DEFAULT_GOOGLE_GROUNDING_DYNAMIC_THRESHOLD' => BotSettingsManager::DEFAULT_GOOGLE_GROUNDING_DYNAMIC_THRESHOLD, ]; } $grounding_flags['allowGoogleSearchGrounding'] = ($settings['provider'] ?? 'OpenAI') === 'Google' && $allow_google_search_grounding_setting; if ($grounding_flags['allowGoogleSearchGrounding']) { $grounding_flags['googleGroundingMode'] = $settings['google_grounding_mode'] ?? $defaults['DEFAULT_GOOGLE_GROUNDING_MODE']; if ($grounding_flags['googleGroundingMode'] === 'MODE_DYNAMIC') { $grounding_flags['googleGroundingDynamicThreshold'] = isset($settings['google_grounding_dynamic_threshold']) ? floatval($settings['google_grounding_dynamic_threshold']) : $defaults['DEFAULT_GOOGLE_GROUNDING_DYNAMIC_THRESHOLD']; } else { $grounding_flags['googleGroundingDynamicThreshold'] = null; } } else { $grounding_flags['googleGroundingMode'] = null; $grounding_flags['googleGroundingDynamicThreshold'] = null; } return $grounding_flags; }